input.command:
# Add file-realm volume and volumeMounts to the 'es' StatefulSet
kubectl -n elasticsearch patch statefulset es --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "file-realm",
      "secret": {
        "secretName": "es-file-realm-aggregate",
        "items": [
          {"key": "users", "path": "users"},
          {"key": "users_roles", "path": "users_roles"},
          {"key": "roles.yml", "path": "roles.yml"}
        ]
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users",
      "subPath": "users",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users_roles",
      "subPath": "users_roles",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/roles.yml",
      "subPath": "roles.yml",
      "readOnly": true
    }
  }
]'
echo "es StatefulSet patched: $?"

# Same patch for the 'es-data' StatefulSet
kubectl -n elasticsearch patch statefulset es-data --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "file-realm",
      "secret": {
        "secretName": "es-file-realm-aggregate",
        "items": [
          {"key": "users", "path": "users"},
          {"key": "users_roles", "path": "users_roles"},
          {"key": "roles.yml", "path": "roles.yml"}
        ]
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users",
      "subPath": "users",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users_roles",
      "subPath": "users_roles",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/roles.yml",
      "subPath": "roles.yml",
      "readOnly": true
    }
  }
]'
echo "es-data StatefulSet patched: $?"

