# Create the 'read' role via Elasticsearch API (using ops-user which has superuser access)
kubectl -n elasticsearch exec curl-test -- curl -s -k \
  -u ops-user:opspass \
  -XPUT "https://es-http.elasticsearch.svc:9200/_security/role/read" \
  -H "Content-Type: application/json" \
  -d '{
    "indices": [
      {
        "names": ["*"],
        "privileges": ["read"]
      }
    ]
  }'
